form:Form.form:Scripts:
		function LoadForm()
{ 
 if (Ctrl('main').GetMode() !="LIST" && Ctrl('main').GetMode() !="NEW")
  	SetDisponible();
}
function SetDisponible()
{
	var cantDisp;  
  var nSQL = GetProxy().SQLService();
  cantDisp = nSQL.GetOBJ(Ctrl("main").getResource("QRY_EXISTENCIAS"), "<PARAM code=\""+Ctrl('c_uniforme').GetXValue()+"\" />");
 	Ctrl("existencias").SetXValue(cantDisp.stock);
}
